const claudeResponse = $input.first().json;
let score = 0;
let reason = 'Claude returned malformed JSON — skipping this lead';
try {
  const text = claudeResponse.content[0].text.trim();
  const parsed = JSON.parse(text);
  score = parsed.score;
  reason = parsed.reason;
} catch (e) {
  // score stays 0, IF node routes to false branch and silently drops this lead
}

// Carry lead fields from Split by Lead through the Claude HTTP call
// .item gives the current batch item (not the first item across all batches)
const lead = $('Split by Lead').item.json;

return [{
  json: {
    first_name: lead.first_name,
    last_name: lead.last_name,
    full_name: lead.full_name,
    title: lead.title,
    email: lead.email,
    company: lead.company,
    website: lead.website,
    city: lead.city,
    state: lead.state,
    score,
    reason
  }
}];

